-- e1000000 시리즈 중 충돌 없이 삽입된 중복 데이터 정리
-- e1000000-..006~009 (광주 태전, 여주 세종, 여주 점동, 용인 처인)은 삭제
-- f1000000 시리즈가 정본

DELETE FROM public.housing_listings WHERE neighborhood_id IN (
  'e1000000-0000-0000-0000-000000000006',
  'e1000000-0000-0000-0000-000000000007',
  'e1000000-0000-0000-0000-000000000008',
  'e1000000-0000-0000-0000-000000000009'
);

DELETE FROM public.neighborhoods WHERE id IN (
  'e1000000-0000-0000-0000-000000000006',
  'e1000000-0000-0000-0000-000000000007',
  'e1000000-0000-0000-0000-000000000008',
  'e1000000-0000-0000-0000-000000000009'
);
